import { slugify } from './utils.js';
const modes = ['fixed', 'sum', 'percent_discount'];
const statuses = ['active', 'draft', 'archived'];
const text = (v = '') => String(v || '').trim();
const num = (v, f = 0) => Number.isFinite(Number(v)) ? Math.trunc(Number(v)) : f;
const bool = (v, f = false) => v === undefined || v === null || v === '' ? f : v === true || v === 'true' || v === '1' || v === 1;
const pick = (v, a, f) => a.includes(text(v).toLowerCase()) ? text(v).toLowerCase() : f;
const asJson = (v, f) => Array.isArray(v) || (v && typeof v === 'object') ? v : (() => { try { return JSON.parse(v || ''); } catch { return f; } })();
export function normalizeBundleItemInput(item = {}) { return { productId: text(item.productId || item.product_id), variantId: text(item.variantId || item.variant_id), quantity: Math.max(1, num(item.quantity, 1)), required: bool(item.required, true), position: Math.max(0, num(item.position, 0)) }; }
export function normalizeBundleInput(body = {}, existing = {}) { const title = text(body.title || existing.title || 'New bundle'); const items = asJson(body.items, body.items || existing.items || []).map(normalizeBundleItemInput).filter((i) => i.productId); return { title, slug: slugify(body.slug || existing.slug || title), description: text(body.description || existing.description), imageUrl: text(body.imageUrl || existing.imageUrl), pricingMode: pick(body.pricingMode || existing.pricingMode, modes, 'sum'), fixedPriceCents: Math.max(0, num(body.fixedPriceCents ?? existing.fixedPriceCents, 0)), discountBps: Math.min(10000, Math.max(0, num(body.discountBps ?? existing.discountBps, 0))), status: pick(body.status || existing.status, statuses, 'draft'), items }; }
export function bundleItemRecord(row) { if (!row) return null; return { id: row.id || '', bundleId: row.bundle_id || row.bundleId || '', productId: row.product_id || row.productId || '', variantId: row.variant_id || row.variantId || '', quantity: Number(row.quantity || 0), required: Boolean(Number(row.required ?? 1)), position: Number(row.position || 0), productTitle: row.product_title || row.productTitle || '', sku: row.sku || row.product_sku || row.productSku || '', unitPriceCents: Number(row.unit_price_cents ?? row.unitPriceCents ?? row.price_cents ?? row.priceCents ?? 0), inventoryOnHand: Number(row.inventory_on_hand ?? row.inventoryOnHand ?? 0) }; }
export function priceBundle(bundle = {}, items = []) { const subtotalCents = (Array.isArray(items) ? items : []).reduce((sum, item) => sum + Number(item.unitPriceCents || item.priceCents || 0) * Math.max(1, Number(item.quantity || 1)), 0); if (bundle.pricingMode === 'fixed') { const totalCents = Math.max(0, Number(bundle.fixedPriceCents || 0)); return { subtotalCents, totalCents, savingsCents: Math.max(0, subtotalCents - totalCents), mode: 'fixed' }; } if (bundle.pricingMode === 'percent_discount') { const savingsCents = Math.floor(subtotalCents * Math.max(0, Number(bundle.discountBps || 0)) / 10000); return { subtotalCents, totalCents: Math.max(0, subtotalCents - savingsCents), savingsCents, mode: 'percent_discount' }; } return { subtotalCents, totalCents: subtotalCents, savingsCents: 0, mode: 'sum' }; }
export function calculateBundleAvailability(items = []) { const required = (Array.isArray(items) ? items : []).filter((i) => i.required !== false); if (!required.length) return { available: true, maxBundles: 0, reason: 'no_required_components' }; const maxBundles = required.reduce((min, item) => Math.min(min, Math.floor(Number(item.inventoryOnHand ?? item.inventory_on_hand ?? 0) / Math.max(1, Number(item.quantity || 1)))), Infinity); const normalized = Number.isFinite(maxBundles) ? Math.max(0, maxBundles) : 0; return { available: normalized > 0, maxBundles: normalized, reason: normalized > 0 ? 'available' : 'insufficient_component_inventory' }; }
export function bundleRecord(row, items = []) { if (!row) return null; const normalizedItems = (Array.isArray(items) ? items : []).map(bundleItemRecord).filter(Boolean).sort((a, b) => a.position - b.position); const base = { id: row.id || '', merchantId: row.merchant_id || row.merchantId || '', title: row.title || '', slug: row.slug || '', description: row.description || '', imageUrl: row.image_url || row.imageUrl || '', pricingMode: row.pricing_mode || row.pricingMode || 'sum', fixedPriceCents: Number(row.fixed_price_cents ?? row.fixedPriceCents ?? 0), discountBps: Number(row.discount_bps ?? row.discountBps ?? 0), status: row.status || 'draft', createdAt: row.created_at || row.createdAt || '', updatedAt: row.updated_at || row.updatedAt || '', items: normalizedItems }; return { ...base, pricing: priceBundle(base, normalizedItems), availability: calculateBundleAvailability(normalizedItems) }; }
export function expandBundleLine(bundle = {}, quantity = 1) { const multiplier = Math.max(1, num(quantity, 1)); return (Array.isArray(bundle.items) ? bundle.items : []).map((item) => ({ productId: item.productId, variantId: item.variantId || '', quantity: Math.max(1, Number(item.quantity || 1)) * multiplier, required: item.required !== false, bundleId: bundle.id || '', bundleTitle: bundle.title || '' })); }
